query:
CREATE TABLE IF NOT EXISTS upload_text (
  id INT AUTO_INCREMENT PRIMARY KEY,
  upload_id INTEGER NOT NULL REFERENCES intake_uploads(id) ON DELETE CASCADE,
  intake_id INTEGER NOT NULL REFERENCES intakes(id) ON DELETE CASCADE,
  text_content TEXT NOT NULL,
  word_count INTEGER,
  extracted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,
  UNIQUE(upload_id)
);

CREATE INDEX IF NOT EXISTS idx_upload_text_intake_id ON upload_text(intake_id);
CREATE INDEX IF NOT EXISTS idx_upload_text_upload_id ON upload_text(upload_id);

